.main-navbar {
  display: flex;
  align-items: center;
  gap: var(--space-lg);
  background: var(--color-surface);
  padding: 0 var(--space-lg);
  box-shadow: var(--shadow-md);
  margin-bottom: var(--space-lg);
  position: relative;
  border-radius: 0;
  width: 100vw;
  left: 50%;
  transform: translateX(-50%);
  min-height: 64px;
}
.menu-icon {
  display: none;
  flex-direction: column;
  justify-content: center;
  cursor: pointer;
  width: 36px;
  height: 36px;
  margin-right: var(--space-md);
}
.menu-icon span {
  display: block;
  height: 4px;
  width: 28px;
  background: var(--color-primary);
  border-radius: 2px;
  margin: 4px 0;
  transition: 0.3s;
}
.menu-links {
  display: flex;
  gap: var(--space-lg);
}
.menu-links a {
  color: var(--color-primary);
  font-size: var(--font-size-lg);
  font-family: var(--font-family-accent);
  text-decoration: none;
  padding: var(--space-xs) var(--space-md);
  border-radius: var(--radius-md);
  transition: var(--transition-fast);
  display: inline-flex;
  align-items: center;
}
.menu-links a .icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  margin-right: 8px;
  color: var(--color-primary);
}
.menu-links a .label { display: inline-block; }
.menu-links a.active,
.menu-links a:hover {
  background: var(--color-accent);
  color: #fff;
}
@media (max-width: 700px) {
  .main-navbar {
    padding: var(--space-md);
    border-radius: 0 0 var(--radius-lg) var(--radius-lg);
    width: auto;
    left: 0;
    transform: none;
  }
  .menu-icon {
    display: flex;
  }
  .menu-links {
    display: none;
    flex-direction: column;
    position: absolute;
    top: 100%;
    left: 0;
    width: 100%;
    background: var(--color-surface);
    box-shadow: var(--shadow-md);
    border-radius: 0 0 var(--radius-lg) var(--radius-lg);
    padding: var(--space-md);
    z-index: 10;
  }
  .menu-toggle:checked ~ .menu-links {
    display: flex;
  }
}

/* Bottom tabbar styles (mobile-only) */
.bottom-tabbar {
  display: none;
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  height: 60px;
  background: var(--color-surface);
  box-shadow: 0 -2px 8px rgba(0,0,0,0.08);
  display: flex;
  gap: 4px;
  justify-content: space-around;
  align-items: center;
  z-index: 50;
}
.bottom-tabbar a {
  color: var(--color-primary);
  text-decoration: none;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  font-size: 12px;
  width: 25%;
  height: 100%;
}
.bottom-tabbar a .icon { margin-bottom: 4px; }
.bottom-tabbar a.active, .bottom-tabbar a:active { background: transparent; color: var(--color-accent); }

/* Show tabbar on very small screens, keep hamburger for small tablets */
@media (max-width: 480px) {
  .main-navbar { display: none; }
  .bottom-tabbar { display: flex; }
}

@media (min-width: 481px) and (max-width: 700px) {
  .bottom-tabbar { display: none; }
}

